code.C:
#include <stdio.h>
int findMin(int* nums, int numsSize) {
    int minVal = nums[0];
    for (int i = 1; i < numsSize; i++) {
        if (nums[i] < minVal) {
            minVal = nums[i];
        }
    }
    return minVal;
}

